function resolveEx(ex, wp) {
  if (ex.role === 'note') return { isNote: true, text: ex.name };
  let result;
  if (ex.role === 'main') {
    let intensity;
    if (ex.int === 'rir') intensity = `RIR ${wp.rir}`;
    else if (ex.pctRef) intensity = `${wp.pct} ${ex.pctRef}`;
    else intensity = wp.pct;
    result = { name: ex.name, sets: ex.sets || wp.sets, reps: ex.reps || wp.reps, intensity, notes: ex.notes };
  } else if (ex.role === 'param') {
    const pr = wp[ex.from];
    result = { name: ex.name, sets: pr.sets, reps: pr.reps, intensity: pr.intensity, notes: ex.notes };
  } else {
    result = { name: ex.name, sets: ex.sets, reps: ex.reps, intensity: ex.intensity, notes: ex.notes };
  }
  if (ex.focus) result.focus = ex.focus;
  if (ex.cue) result.cue = ex.cue;
  if (ex.role) result.role = ex.role;
  if (ex.set != null) result.set = ex.set;
  return result;
}
