function genF3Weeks() {
  return F3_PROG.map(wp => ({
    num: wp.num, label: wp.label, load: wp.load, weekScience: wp.weekScience,
    days: F3_DAYS.map(d => ({
      day: d.day, name: d.name, cat: d.cat, dayScience: d.dayScience,
      workoutScience: d.workoutScience,
      exercises: d.exercises ? d.exercises.map(ex => resolveEx(ex, wp)) : undefined,
      notes: d.notes,
    })),
  }));
}
function buildPhaseDay(d, wp) {
  if (d.notes && !d.blocks) return { day: d.day, name: d.name || 'Recuperación', cat: d.cat, notes: d.notes, dayScience: d.dayScience, workoutScience: d.workoutScience };
  const result = { day: d.day, cat: d.cat, dual: d.dual, blocks: [], dayScience: d.dayScience, workoutScience: d.workoutScience };
  d.blocks.forEach(blk => {
    if (blk.type === 'lift') {
      result.blocks.push({ tag: blk.tag, cat: blk.cat, type: 'lift', exercises: blk.exercises.map(ex => resolveEx(ex, wp)) });
    } else if (blk.type === 'speed') {
      const bullets = [...blk.fixed];
      if (blk.sprintFrom && wp[blk.sprintFrom]) bullets.push({ bold: true, text: wp[blk.sprintFrom] });
      if (blk.tail) bullets.push(...blk.tail);
      result.blocks.push({ tag: blk.tag, cat: blk.cat, type: 'speed', bullets });
    } else if (blk.type === 'note') {
      result.blocks.push({ tag: blk.tag, cat: blk.cat, type: 'note', text: blk.noteText });
    }
  });
  return result;
}
function genF4Weeks() { return F4_PROG.map(wp => ({ num: wp.num, label: wp.label, load: wp.load, weekScience: wp.weekScience, days: F4_DAYS.map(d => buildPhaseDay(d, wp)) })); }
function genF5Weeks() { return F5_PROG.map(wp => ({ num: wp.num, label: wp.label, load: wp.load, weekScience: wp.weekScience, days: F5_DAYS.map(d => buildPhaseDay(d, wp)) })); }
